func (a IPCAPI) FindChannelsForDevice(c *gin.Context, in *ipc.FindDeviceInput) (any, error) {
	ctx := c.Request.Context()
	items, total, err := a.ipc.FindChannelsForDevice(ctx, in)
	fillDeviceRecordMode(items)

	// 收集所有通道 ID 用于批量查询录像
	var cids []string
	for _, dev := range items {
		for _, ch := range dev.Children {
			cids = append(cids, ch.ID)
		}
	}

	// 批量查询哪些通道有录像
	hasRecordingMap, _ := a.recordingCore.HasRecordings(ctx, cids)

	// 为每个通道设置 has_recording 标记
	for _, dev := range items {
		for _, ch := range dev.Children {
			ch.HasRecording = hasRecordingMap[ch.ID]
		}
	}

	// 按照在线优先排序
	sort.SliceStable(items, func(i, j int) bool {
		return items[i].IsOnline && !items[j].IsOnline
	})
	// 按照第 1 个通道是否在线排序
	sort.SliceStable(items, func(i, j int) bool {
		if len(items[i].Children) > 0 && len(items[j].Children) > 0 {
			return items[i].Children[0].IsOnline && !items[j].Children[0].IsOnline
		}
		return false
	})

	return gin.H{"items": items, "total": total}, err
}

// fillDeviceRecordMode 统一设备接口返回：record_mode 为空时回填默认值。
func fillDeviceRecordMode(items []*ipc.Device) {
	for _, dev := range items {
		if dev == nil {
			continue
		}
		dev.Ext.RecordMode = dev.Ext.GetRecordMode()
		for _, ch := range dev.Children {
			if ch == nil {
				continue
			}
			ch.Ext.RecordMode = ch.Ext.GetRecordMode()
		}
	}
}

