// gbDeviceQuery 执行 GB 附录 A.2.4 统一设备查询命令。
func (a IPCAPI) gbDeviceQuery(c *gin.Context, in *gbDeviceQueryInput) (any, error) {
	deviceID := c.Param("id")
	out, err := a.ipc.GBDeviceQuery(c.Request.Context(), deviceID, &ipc.GBDeviceQueryInput{
		TargetID:   in.TargetID,
		Action:     in.Action,
		Timeout:    in.Timeout,
		ConfigType: in.ConfigType,
		Interval:   in.Interval,
		Start:      in.Start,
		End:        in.End,
	})
	if err != nil {
		return nil, ErrDevice.SetMsg(err.Error())
	}
	resp := gbDeviceQueryOutput{
		SN:         out.SN,
		CmdType:    out.CmdType,
		DeviceID:   out.DeviceID,
		Result:     out.Result,
		XML:        out.XML,
		Data:       out.Data,
		AppendixA4: make([]gbAppendixA4Output, 0, len(out.AppendixA4)),
	}
	for _, item := range out.AppendixA4 {
		resp.AppendixA4 = append(resp.AppendixA4, gbAppendixA4Output{
			Type:      item.Type,
			CmdType:   item.CmdType,
			Path:      item.Path,
			Fields:    item.Fields,
			RawXML:    item.RawXML,
			UpdatedAt: item.UpdatedAt,
		})
	}
	return resp, nil
}

